import React, { useState, useCallback, useEffect, useRef } from 'react';
import { puzzles } from './data/puzzles';
import { bridgeKey, parseKey, canAddBridge, computeCurrentCounts, isVictory } from './utils/hashiLogic';

const GRID_SIZE = 40;
const ISLAND_RADIUS = 16;

function App() {
  const [puzzleIndex, setPuzzleIndex] = useState(0);
  const [bridges, setBridges] = useState(new Map());
  const [selectedIsland, setSelectedIsland] = useState(null);
  const [cursorIndex, setCursorIndex] = useState(0);
  const [error, setError] = useState(null);
  const [victory, setVictory] = useState(false);
  const [keyboardMode, setKeyboardMode] = useState(false);
  const svgRef = useRef(null);

  const currentPuzzle = puzzles[puzzleIndex];
  const islands = currentPuzzle.islands;

  // Reset when puzzle changes
  const handlePuzzleChange = useCallback((e) => {
    setPuzzleIndex(Number(e.target.value));
    setBridges(new Map());
    setSelectedIsland(null);
    setCursorIndex(0);
    setError(null);
    setVictory(false);
  }, []);

  // Reset button
  const handleReset = useCallback(() => {
    setBridges(new Map());
    setSelectedIsland(null);
    setError(null);
    setVictory(false);
  }, []);

  // Toggle bridge between two islands (cycle: none -> single -> double -> none)
  const toggleBridge = useCallback((fromIsland, toIsland) => {
    const key = bridgeKey(fromIsland, toIsland);
    const current = bridges.get(key) || 0;

    if (current === 0) {
      // Try to add single
      const result = canAddBridge(islands, bridges, fromIsland, toIsland, 1);
      if (!result.valid) {
        setError(result.error);
        return;
      }
      setError(null);
      const newBridges = new Map(bridges);
      newBridges.set(key, 1);
      setBridges(newBridges);
      // Check victory
      if (isVictory(islands, newBridges)) setVictory(true);
    } else if (current === 1) {
      // Try to add second bridge
      const result = canAddBridge(islands, bridges, fromIsland, toIsland, 1);
      if (!result.valid) {
        // If can't add, remove instead (cycle to none)
        setError(null);
        const newBridges = new Map(bridges);
        newBridges.delete(key);
        setBridges(newBridges);
        setVictory(false);
        return;
      }
      setError(null);
      const newBridges = new Map(bridges);
      newBridges.set(key, 2);
      setBridges(newBridges);
      if (isVictory(islands, newBridges)) setVictory(true);
    } else {
      // current === 2, cycle to none
      setError(null);
      const newBridges = new Map(bridges);
      newBridges.delete(key);
      setBridges(newBridges);
      setVictory(false);
    }
  }, [bridges, islands]);

  // Remove bridge entirely
  const removeBridge = useCallback((fromIsland, toIsland) => {
    const key = bridgeKey(fromIsland, toIsland);
    const current = bridges.get(key) || 0;
    if (current > 0) {
      setError(null);
      const newBridges = new Map(bridges);
      newBridges.delete(key);
      setBridges(newBridges);
      setVictory(false);
    }
  }, [bridges]);

  // Handle island click
  const handleIslandClick = useCallback((island, e) => {
    // Right-click or Ctrl+click = remove
    if (e.button === 2 || e.ctrlKey) {
      if (selectedIsland !== null) {
        removeBridge(selectedIsland, island);
        setSelectedIsland(null);
      }
      return;
    }

    if (selectedIsland === null) {
      setSelectedIsland(island);
      setError(null);
    } else if (selectedIsland.id === island.id) {
      // Clicking same island deselects
      setSelectedIsland(null);
    } else {
      toggleBridge(selectedIsland, island);
      setSelectedIsland(null);
    }
  }, [selectedIsland, toggleBridge, removeBridge]);

  // Handle right-click on SVG for bridge removal
  const handleContextMenu = useCallback((e) => {
    e.preventDefault();
  }, []);

  // Keyboard navigation
  useEffect(() => {
    const handleKeyDown = (e) => {
      if (e.key === 'Escape') {
        setSelectedIsland(null);
        setKeyboardMode(true);
        return;
      }

      if (e.key === 'Enter') {
        setKeyboardMode(true);
        const currentIsland = islands[cursorIndex];
        if (selectedIsland === null) {
          setSelectedIsland(currentIsland);
          setError(null);
        } else if (selectedIsland.id === currentIsland.id) {
          setSelectedIsland(null);
        } else {
          toggleBridge(selectedIsland, currentIsland);
          setSelectedIsland(null);
        }
        return;
      }

