          if (e.key === 'ArrowLeft' && dx < 0 && Math.abs(dy) <= Math.abs(dx)) valid = true;
          if (e.key === 'ArrowDown' && dy > 0 && Math.abs(dx) <= Math.abs(dy)) valid = true;
          if (e.key === 'ArrowUp' && dy < 0 && Math.abs(dx) <= Math.abs(dy)) valid = true;

