import React, { useState, useCallback, useEffect, useRef } from 'react';
import { puzzles } from './data/puzzles';
import { bridgeKey, parseKey, canAddBridge, computeCurrentCounts, isVictory } from './utils/hashiLogic';

const GRID_SIZE = 40;
const ISLAND_RADIUS = 16;

function App() {
  const [puzzleIndex, setPuzzleIndex] = useState(0);
  const [bridges, setBridges] = useState(new Map());
  const [selectedIsland, setSelectedIsland] = useState(null);
  const [cursorIndex, setCursorIndex] = useState(0);
  const [error, setError] = useState(null);
  const [victory, setVictory] = useState(false);
  const [keyboardMode, setKeyboardMode] = useState(false);
  const svgRef = useRef(null);

  const currentPuzzle = puzzles[puzzleIndex];
  const islands = currentPuzzle.islands;

  const handlePuzzleChange = useCallback((e) => {
    setPuzzleIndex(Number(e.target.value));
    setBridges(new Map());
    setSelectedIsland(null);
    setCursorIndex(0);
    setError(null);
    setVictory(false);
  }, []);

  const handleReset = useCallback(() => {
    setBridges(new Map());
    setSelectedIsland(null);
    setError(null);
    setVictory(false);
  }, []);

  // Toggle bridge: none -> single -> double -> none
  const toggleBridge = useCallback((fromIsland, toIsland) => {
    const key = bridgeKey(fromIsland, toIsland);
    const current = bridges.get(key) || 0;

    if (current === 0) {
      const result = canAddBridge(islands, bridges, fromIsland, toIsland, 1);
      if (!result.valid) {
        setError(result.error);
        return;
      }
      setError(null);
      const newBridges = new Map(bridges);
      newBridges.set(key, 1);
      setBridges(newBridges);
      if (isVictory(islands, newBridges)) setVictory(true);
      else setVictory(false);
    } else if (current === 1) {
      const result = canAddBridge(islands, bridges, fromIsland, toIsland, 1);
      if (!result.valid) {
        setError(result.error);
        return;
      }
      setError(null);
      const newBridges = new Map(bridges);
      newBridges.set(key, 2);
      setBridges(newBridges);
      if (isVictory(islands, newBridges)) setVictory(true);
      else setVictory(false);
    } else {
      // current === 2, cycle to none
      setError(null);
      const newBridges = new Map(bridges);
      newBridges.delete(key);
      setBridges(newBridges);
      setVictory(false);
    }
  }, [bridges, islands]);

  // Remove bridge entirely
  const removeBridgeByKey = useCallback((key) => {
    const current = bridges.get(key) || 0;
    if (current > 0) {
      setError(null);
      const newBridges = new Map(bridges);
      newBridges.delete(key);
      setBridges(newBridges);
      setVictory(false);
    }
  }, [bridges]);

  // Handle island click
  const handleIslandClick = useCallback((island, e) => {
    if (e.button === 2 || e.ctrlKey) {
      // Right-click or ctrl+click on island with selection: remove bridge
      if (selectedIsland !== null && selectedIsland.id !== island.id) {
        const key = bridgeKey(selectedIsland, island);
        removeBridgeByKey(key);
        setSelectedIsland(null);
      }
      return;
    }

    if (selectedIsland === null) {
      setSelectedIsland(island);
      setError(null);
    } else if (selectedIsland.id === island.id) {
      setSelectedIsland(null);
    } else {
      toggleBridge(selectedIsland, island);
      setSelectedIsland(null);
    }
  }, [selectedIsland, toggleBridge, removeBridgeByKey]);

  // Handle right-click/ctrl+click on bridge lines
  const handleBridgeClick = useCallback((key, e) => {
    if (e.button === 2 || e.ctrlKey) {
      e.stopPropagation();
      removeBridgeByKey(key);
    }
  }, [removeBridgeByKey]);

  const handleBridgeContextMenu = useCallback((key, e) => {
    e.preventDefault();
    e.stopPropagation();
    removeBridgeByKey(key);
  }, [removeBridgeByKey]);

  const handleContextMenu = useCallback((e) => {
    e.preventDefault();
  }, []);

  // Keyboard navigation
  useEffect(() => {
    const handleKeyDown = (e) => {
      if (e.key === 'Escape') {
        setSelectedIsland(null);
        setKeyboardMode(true);
        return;
      }

      if (e.key === 'Enter') {
        setKeyboardMode(true);
        const currentIsland = islands[cursorIndex];
        if (selectedIsland === null) {
          setSelectedIsland(currentIsland);
          setError(null);
        } else if (selectedIsland.id === currentIsland.id) {
          setSelectedIsland(null);
        } else {
          toggleBridge(selectedIsland, currentIsland);
          setSelectedIsland(null);
        }
        return;
      }

      if (['ArrowUp', 'ArrowDown', 'ArrowLeft', 'ArrowRight'].includes(e.key)) {
        e.preventDefault();
        setKeyboardMode(true);
        const current = islands[cursorIndex];
        let bestIndex = cursorIndex;
        let bestDist = Infinity;

        for (let i = 0; i < islands.length; i++) {
          if (i === cursorIndex) continue;
          const target = islands[i];
          const dx = target.x - current.x;
          const dy = target.y - current.y;

          let valid = false;
          if (e.key === 'ArrowRight' && dx > 0) valid = true;
          if (e.key === 'ArrowLeft' && dx < 0) valid = true;
          if (e.key === 'ArrowDown' && dy > 0) valid = true;
          if (e.key === 'ArrowUp' && dy < 0) valid = true;

          if (valid) {
            const dist = Math.abs(dx) + Math.abs(dy);
            if (dist < bestDist) {
              bestDist = dist;
              bestIndex = i;
            }
          }
        }
        setCursorIndex(bestIndex);
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [islands, cursorIndex, selectedIsland, toggleBridge]);

  // Render bridges
  const renderBridges = () => {
    const lines = [];
    for (const [key, count] of bridges) {
      if (count === 0) continue;
      const { x1, y1, x2, y2 } = parseKey(key);
      const px1 = x1 * GRID_SIZE;
      const py1 = y1 * GRID_SIZE;
      const px2 = x2 * GRID_SIZE;
      const py2 = y2 * GRID_SIZE;

      if (count === 1) {
        lines.push(
          <line
            key={key}
            x1={px1} y1={py1} x2={px2} y2={py2}
            stroke="#0f0"
            strokeWidth="3"
            onClick={(e) => handleBridgeClick(key, e)}
            onContextMenu={(e) => handleBridgeContextMenu(key, e)}
            style={{ cursor: 'pointer' }}
          />
        );
      } else if (count === 2) {
        const isHorizontal = y1 === y2;
        const offset = 4;
        if (isHorizontal) {
          lines.push(
            <line
              key={key + '-a'}
              x1={px1} y1={py1 - offset} x2={px2} y2={py2 - offset}
              stroke="#0f0"
              strokeWidth="3"
              onClick={(e) => handleBridgeClick(key, e)}
              onContextMenu={(e) => handleBridgeContextMenu(key, e)}
              style={{ cursor: 'pointer' }}
            />
          );
          lines.push(
            <line
              key={key + '-b'}
              x1={px1} y1={py1 + offset} x2={px2} y2={py2 + offset}
              stroke="#0f0"
              strokeWidth="3"
              onClick={(e) => handleBridgeClick(key, e)}
              onContextMenu={(e) => handleBridgeContextMenu(key, e)}
              style={{ cursor: 'pointer' }}
            />
          );
        } else {
          lines.push(
            <line
              key={key + '-a'}
              x1={px1 - offset} y1={py1} x2={px2 - offset} y2={py2}
              stroke="#0f0"
              strokeWidth="3"
              onClick={(e) => handleBridgeClick(key, e)}
              onContextMenu={(e) => handleBridgeContextMenu(key, e)}
              style={{ cursor: 'pointer' }}
            />
          );
          lines.push(
            <line
              key={key + '-b'}
              x1={px1 + offset} y1={py1} x2={px2 + offset} y2={py2}
              stroke="#0f0"
              strokeWidth="3"
              onClick={(e) => handleBridgeClick(key, e)}
              onContextMenu={(e) => handleBridgeContextMenu(key, e)}
              style={{ cursor: 'pointer' }}
            />
          );
        }
      }
    }
    return lines;
  };

  // Render islands
  const renderIslands = () => {
    return islands.map((island) => {
      const px = island.x * GRID_SIZE;
      const py = island.y * GRID_SIZE;
      const isSelected = selectedIsland && selectedIsland.id === island.id;

      return (
        <g key={island.id}
          onClick={(e) => handleIslandClick(island, e)}
          onContextMenu={(e) => {
            e.preventDefault();
            e.stopPropagation();
            if (selectedIsland !== null && selectedIsland.id !== island.id) {
              const key = bridgeKey(selectedIsland, island);
              removeBridgeByKey(key);
              setSelectedIsland(null);
            }
          }}
          style={{ cursor: 'pointer' }}
        >
          <circle
            cx={px} cy={py} r={ISLAND_RADIUS}
            fill="black"
            stroke={isSelected ? "#ff0" : "#0f0"}
            strokeWidth={isSelected ? 3 : 2}
          />
          <text
            x={px} y={py}
            textAnchor="middle"
            dominantBaseline="central"
            fill="#0f0"
            fontSize="14"
            fontFamily="monospace"
            style={{ pointerEvents: 'none' }}
          >
            {island.value}
          </text>
        </g>
      );
    });
  };

  // Render keyboard cursor (rect, NOT circle)
  const renderCursor = () => {
    if (!keyboardMode) return null;
    const island = islands[cursorIndex];
    if (!island) return null;
    const px = island.x * GRID_SIZE;
    const py = island.y * GRID_SIZE;
    const size = ISLAND_RADIUS + 6;

    return (
      <rect
        x={px - size} y={py - size}
        width={size * 2} height={size * 2}
        fill="none"
        stroke="#0ff"
        strokeWidth="2"
        strokeDasharray="4 2"
        style={{ pointerEvents: 'none' }}
      />
    );
  };

  return (
    <div style={{ margin: 0, padding: 0 }}>
      <div style={{ padding: '8px', display: 'flex', gap: '12px', alignItems: 'center' }}>
        <select value={puzzleIndex} onChange={handlePuzzleChange} style={{
          background: 'black', color: '#0f0', border: '1px solid #0f0',
          fontFamily: 'monospace', fontSize: '14px', padding: '4px'
        }}>
          {puzzles.map((p, i) => (
            <option key={p.id} value={i}>{p.name}</option>
          ))}
        </select>
        <button onClick={handleReset} style={{
          background: 'black', color: '#0f0', border: '1px solid #0f0',
          fontFamily: 'monospace', fontSize: '14px', padding: '4px 8px', cursor: 'pointer'
        }}>Reset</button>
        {error && <span className="error-message" style={{ color: '#f00', fontFamily: 'monospace' }}>{error}</span>}
        {victory && <span className="victory-banner" style={{ color: '#0f0', fontFamily: 'monospace', fontSize: '20px', fontWeight: 'bold' }}>SOLVED!</span>}
      </div>
      <svg
        ref={svgRef}
        width={800}
        height={600}
        style={{ display: 'block' }}
        onContextMenu={handleContextMenu}
      >
        {renderBridges()}
        {renderIslands()}
        {renderCursor()}
      </svg>
    </div>
  );
}

export default App;
ENDOFFILE

